def localizar_repositorio():
    """
    Localiza automaticamente a pasta que contém o diretório .git.
    """
    pasta = Path(__file__).resolve().parent
    while pasta != pasta.parent:
        if (pasta / ".git").exists():
            return pasta
        pasta = pasta.parent
    raise RuntimeError("Repositório Git não encontrado.")

